def _compact_sample_gate_timer_stats(
    records: list[Mapping[str, Any]],
    *,
    value_key: str = "sec",
) -> dict[str, Any]:
    if not records:
        return {
            "count": 0,
            "sum_sec": 0.0,
            "min_sec": 0.0,
            "max_sec": 0.0,
            "p50_sec": 0.0,
            "p95_sec": 0.0,
            "slowest_call_index": 0,
            "slowest_iteration": 0,
            "slowest_measured_iteration": 0,
            "slowest_sample_seed": 0,
            "slowest_sample_row_count": 0,
            "slowest_sampled_pair_count": 0,
            "slowest_terminal_sample_row_count": 0,
            "slowest_source_record_window_checksum": 0,
        }
    values = np.asarray(
        [float(record.get(value_key) or 0.0) for record in records],
        dtype=np.float64,
    )
    slowest_index = int(values.argmax())
    slowest_record = records[slowest_index]
    return {
        "count": int(values.size),
        "sum_sec": float(values.sum()),
        "min_sec": float(values.min()),
        "max_sec": float(values.max()),
        "p50_sec": float(np.percentile(values, 50)),
        "p95_sec": float(np.percentile(values, 95)),
        "slowest_call_index": int(slowest_record.get("call_index") or 0),
        "slowest_iteration": int(slowest_record.get("iteration") or 0),
        "slowest_measured_iteration": int(
            slowest_record.get("measured_iteration") or 0
        ),
        "slowest_sample_seed": int(slowest_record.get("sample_seed") or 0),
        "slowest_sample_row_count": int(slowest_record.get("sample_row_count") or 0),
        "slowest_sampled_pair_count": int(slowest_record.get("sampled_pair_count") or 0),
        "slowest_terminal_sample_row_count": int(
            slowest_record.get("terminal_sample_row_count") or 0
        ),
        "slowest_source_record_window_checksum": int(
            slowest_record.get("source_record_window_checksum") or 0
        ),
    }


def _compact_sample_gate_call_trace_records(
    records: list[Mapping[str, Any]],
    *,
    limit: int = 160,
) -> list[dict[str, Any]]:
    if not records:
        return []
    max_measured_iteration = max(
        (int(record.get("measured_iteration") or 0) for record in records),
        default=0,
    )
    first_cut = max_measured_iteration // 3
    second_cut = (2 * max_measured_iteration) // 3

    def measured_third(measured_iteration: int) -> str:
        if measured_iteration <= 0:
            return "warmup_or_unknown"
        if measured_iteration <= first_cut:
            return "early"
        if measured_iteration <= second_cut:
            return "mid"
        return "late"

    output: list[dict[str, Any]] = []
    for record in sorted(
        records,
        key=lambda item: int(item.get("call_index") or 0),
    )[:limit]:
        measured_iteration = int(record.get("measured_iteration") or 0)
        item: dict[str, Any] = {
            "measured_window_third": measured_third(measured_iteration),
        }
        for field in _COMPACT_SAMPLE_GATE_TRACE_INT_FIELDS:
            item[field] = int(record.get(field) or 0)
        for output_key, record_key in _COMPACT_SAMPLE_GATE_TRACE_FLOAT_FIELDS:
            item[output_key] = float(record.get(record_key) or 0.0)
        output.append(item)
    return output


