def _runtime_step_phase_distribution_stats(
    records: list[Mapping[str, Any]],
) -> dict[str, float]:
    stats: dict[str, float] = {}
    for output_prefix, record_key in _RUNTIME_STEP_PHASE_TIMER_FIELDS:
        if records:
            values = np.asarray(
                [float(record.get(record_key) or 0.0) for record in records],
                dtype=np.float64,
            )
            stats[f"{output_prefix}_sum_sec"] = float(values.sum())
            stats[f"{output_prefix}_min_sec"] = float(values.min())
            stats[f"{output_prefix}_max_sec"] = float(values.max())
            stats[f"{output_prefix}_p50_sec"] = float(np.percentile(values, 50))
            stats[f"{output_prefix}_p95_sec"] = float(np.percentile(values, 95))
        else:
            for stat_name in _RUNTIME_STEP_PHASE_STAT_NAMES:
                stats[f"{output_prefix}_{stat_name}"] = 0.0
    return stats


def _runtime_step_basic_stats(
    records: list[Mapping[str, Any]],
    *,
    value_key: str = "sec",
) -> dict[str, float | int]:
    if not records:
        return {
            "count": 0,
            "sum_sec": 0.0,
            "min_sec": 0.0,
            "max_sec": 0.0,
            "p50_sec": 0.0,
            "p95_sec": 0.0,
        }
    values = np.asarray(
        [float(record.get(value_key) or 0.0) for record in records],
        dtype=np.float64,
    )
    return {
        "count": int(values.size),
        "sum_sec": float(values.sum()),
        "min_sec": float(values.min()),
        "max_sec": float(values.max()),
        "p50_sec": float(np.percentile(values, 50)),
        "p95_sec": float(np.percentile(values, 95)),
    }


def _runtime_step_prefixed_basic_stats(
    prefix: str,
    records: list[Mapping[str, Any]],
) -> dict[str, float | int]:
    return {
        f"{prefix}_{key}": value
        for key, value in _runtime_step_basic_stats(records).items()
    }


def _runtime_step_sum(records: list[Mapping[str, Any]], value_key: str) -> float:
    return float(sum(float(record.get(value_key) or 0.0) for record in records))


