    ("actor_step_wall", "actor_step_wall_sec"),
    ("observation", "observation_sec"),
    ("sample_gate", "sample_gate_sec"),
    ("sample_gate_residual", "sample_gate_residual_sec"),
    ("sample_gate_builder_group_loop", "sample_gate_builder_group_loop_sec"),
