def _compact_runtime_step_top_slowest_records(
    records: list[Mapping[str, Any]],
    *,
    limit: int = 8,
) -> list[dict[str, Any]]:
    slowest = sorted(
        records,
        key=lambda record: float(record.get("sec") or 0.0),
        reverse=True,
    )[:limit]
    output: list[dict[str, Any]] = []
    for record in slowest:
        item: dict[str, Any] = {
            "iteration": int(record.get("iteration") or 0),
            "measured_iteration": int(record.get("measured_iteration") or 0),
            "sample_gate_call_index": int(record.get("sample_gate_call_index") or 0),
            "sample_gate_call_count_delta": int(
                record.get("sample_gate_call_count_delta") or 0
            ),
            "env_trajectory_checksum": int(record.get("env_trajectory_checksum") or 0),
        }
        for field in _RUNTIME_STEP_TOP_SLOWEST_FLOAT_FIELDS:
            item[field] = float(record.get(field) or 0.0)
        output.append(item)
    return output


def _compact_runtime_step_timer_stats(records: list[Mapping[str, Any]]) -> dict[str, Any]:
    if not records:
        empty_stats: dict[str, Any] = {
            "count": 0,
            "sum_sec": 0.0,
            "min_sec": 0.0,
            "max_sec": 0.0,
            "p50_sec": 0.0,
            "p95_sec": 0.0,
            "slowest_iteration": 0,
            "slowest_measured_iteration": 0,
            "slowest_actor_step_wall_sec": 0.0,
            "slowest_observation_sec": 0.0,
            "slowest_compact_rollout_slab_sec": 0.0,
            "slowest_sample_gate_sec": 0.0,
            "slowest_learner_gate_sec": 0.0,
            "slowest_policy_refresh_sec": 0.0,
            "slowest_primary_accounted_sec": 0.0,
            "slowest_primary_residual_sec": 0.0,
            "slowest_env_trajectory_checksum": 0,
            "top_slowest_records": [],
        }
        empty_stats.update(_runtime_step_phase_distribution_stats(records))
        empty_stats.update(_runtime_step_cadence_stats(records))
        return empty_stats
    values = np.asarray([float(record.get("sec") or 0.0) for record in records], dtype=np.float64)
    slowest_index = int(values.argmax())
    slowest_record = records[slowest_index]
    stats: dict[str, Any] = {
        "count": int(values.size),
        "sum_sec": float(values.sum()),
        "min_sec": float(values.min()),
        "max_sec": float(values.max()),
        "p50_sec": float(np.percentile(values, 50)),
        "p95_sec": float(np.percentile(values, 95)),
        "slowest_iteration": int(slowest_record.get("iteration") or 0),
        "slowest_measured_iteration": int(slowest_record.get("measured_iteration") or 0),
        "slowest_actor_step_wall_sec": float(
            slowest_record.get("actor_step_wall_sec") or 0.0
        ),
        "slowest_observation_sec": float(slowest_record.get("observation_sec") or 0.0),
        "slowest_compact_rollout_slab_sec": float(
            slowest_record.get("compact_rollout_slab_sec") or 0.0
        ),
        "slowest_sample_gate_sec": float(slowest_record.get("sample_gate_sec") or 0.0),
        "slowest_learner_gate_sec": float(slowest_record.get("learner_gate_sec") or 0.0),
        "slowest_policy_refresh_sec": float(slowest_record.get("policy_refresh_sec") or 0.0),
        "slowest_primary_accounted_sec": float(
            slowest_record.get("primary_accounted_sec") or 0.0
        ),
        "slowest_primary_residual_sec": float(
            slowest_record.get("primary_residual_sec") or 0.0
        ),
        "slowest_env_trajectory_checksum": int(
            slowest_record.get("env_trajectory_checksum") or 0
        ),
        "top_slowest_records": _compact_runtime_step_top_slowest_records(records),
    }
    stats.update(_runtime_step_phase_distribution_stats(records))
    stats.update(_runtime_step_cadence_stats(records))
    return stats


