class CompactReplayRendererBackedObservationProviderV1:
    """Rebuild scalar-ref replay observations from compact render-state facts."""

    def __init__(
        self,
        *,
        batch_size: int,
        player_count: int = 2,
        renderer: SourceStateBatchedObservationRenderer | None = None,
        stack_storage_dtype: str = HYBRID_STACK_STORAGE_DTYPE_FLOAT32,
        synchronize_device: bool = True,
    ) -> None:
        if int(batch_size) <= 0:
            raise ValueError("batch_size must be positive")
        if int(player_count) <= 0:
            raise ValueError("player_count must be positive")
        if str(stack_storage_dtype) not in HYBRID_STACK_STORAGE_DTYPES:
            raise ValueError(f"unsupported stack_storage_dtype: {stack_storage_dtype!r}")
        self.batch_size = int(batch_size)
        self.player_count = int(player_count)
        self.renderer = renderer if renderer is not None else CpuOracleBatchedObservationRenderer()
        self.stack_storage_dtype = str(stack_storage_dtype)
        self.synchronize_device = bool(synchronize_device)
        dtype = (
            np.float32
            if self.stack_storage_dtype == HYBRID_STACK_STORAGE_DTYPE_FLOAT32
            else np.uint8
        )
        self._stack = np.zeros(
            (self.batch_size, self.player_count, 4, 64, 64),
            dtype=dtype,
        )
        self.bootstrap_step_count = 0
        self.materialized_entry_count = 0
        self.missing_stack_history_count = 0
        self.render_call_count = 0
        self.rendered_frame_count = 0

    def bootstrap_compact_replay_step(self, step: Any) -> None:
        self._reject_transport_observation_payloads(step)
        self._push_render_state_snapshot(
            getattr(step, "render_state_snapshot", None),
            field_name="render_state_snapshot",
        )
        self._reset_done_rows_from_step(step)
        self.bootstrap_step_count += 1

    def materialize_compact_replay_entry(
        self,
        entry: _CompactReplayRingEntry,
    ) -> _CompactReplayRingEntry:
        from curvyzero.training.replay_chunk_v0 import ReplayCompatibilityError

        if self.bootstrap_step_count <= 0:
            self.missing_stack_history_count += 1
            raise ReplayCompatibilityError(
                "compact scalar-ref renderer provider is missing bootstrap stack history"
            )
        previous_observation = self._stack.copy()
        current_step = getattr(entry, "current_step", None)
        if current_step is None:
            raise ReplayCompatibilityError("compact scalar-ref replay entry has no current step")
        self._push_render_state_snapshot(
            getattr(current_step, "render_state_snapshot", None),
            field_name="current_step.render_state_snapshot",
        )
        current_observation = self._stack.copy()
        final_observation = self._terminal_final_observation_for_step(
            current_step,
            current_observation,
        )
        self._reset_done_rows_from_step(current_step)
        previous_step = self._step_with_observation(
            getattr(entry, "previous_step", None),
            previous_observation,
        )
        materialized_current_step = self._step_with_observation(
            current_step,
            current_observation,
        )
        if final_observation is not None:
            materialized_current_step = self._step_with_compact_final_observation(
                materialized_current_step,
                final_observation,
            )
        self.materialized_entry_count += 1
        return _CompactReplayRingEntry(
            previous_step=previous_step,
            current_step=materialized_current_step,
            index_rows=getattr(entry, "index_rows", None),
        )

    def _reject_transport_observation_payloads(self, step: Any) -> None:
        from curvyzero.training.replay_chunk_v0 import ReplayCompatibilityError

        if getattr(step, "observation", None) is not None:
            raise ReplayCompatibilityError(
                "compact scalar-ref provider bootstrap must not carry observation tensors"
            )
        if getattr(step, "resident_observation_replay_snapshot", None) is not None:
            raise ReplayCompatibilityError(
                "compact scalar-ref provider bootstrap must not carry resident snapshots"
            )

    def _push_render_state_snapshot(self, snapshot: Any, *, field_name: str) -> None:
        original_rows, latest = self._render_latest_frames(snapshot, field_name=field_name)
        if original_rows.size <= 0:
            return
        self._stack[original_rows, :, :-1] = self._stack[original_rows, :, 1:]
        self._write_latest_frames(original_rows, latest)

    def _reset_done_rows_from_step(self, step: Any) -> None:
        reset_rows = self._done_rows_from_step(step)
        if reset_rows.size <= 0:
            return
        snapshot = getattr(step, "autoreset_render_state_snapshot", None)
        if snapshot is None:
            from curvyzero.training.replay_chunk_v0 import ReplayCompatibilityError

            raise ReplayCompatibilityError(
                "compact scalar-ref renderer provider needs autoreset render state "
                "for terminal rows"
            )
        rendered_rows, latest = self._render_latest_frames(
            snapshot,
            field_name="autoreset_render_state_snapshot",
        )
        latest_by_row = {int(row): latest[index] for index, row in enumerate(rendered_rows)}
        missing_rows = [int(row) for row in reset_rows if int(row) not in latest_by_row]
        if missing_rows:
            from curvyzero.training.replay_chunk_v0 import ReplayCompatibilityError

            raise ReplayCompatibilityError(
                "compact scalar-ref renderer provider autoreset state is missing "
                f"rows {missing_rows}"
            )
        self._stack[reset_rows] = 0
        reset_latest = np.stack([latest_by_row[int(row)] for row in reset_rows], axis=0)
        self._write_latest_frames(reset_rows, reset_latest)

    def _terminal_final_observation_for_step(
        self,
        step: Any,
        current_observation: np.ndarray,
    ) -> np.ndarray | None:
        terminal_rows = self._done_rows_from_step(step)
        if terminal_rows.size <= 0:
            return None
        final_observation = np.zeros_like(current_observation)
        final_observation[terminal_rows] = current_observation[terminal_rows]
        return final_observation

    def _render_latest_frames(
        self,
        snapshot: Any,
        *,
        field_name: str,
    ) -> tuple[np.ndarray, np.ndarray]:
        from curvyzero.training.replay_chunk_v0 import ReplayCompatibilityError

        if snapshot is None:
            self.missing_stack_history_count += 1
            raise ReplayCompatibilityError(
                f"compact scalar-ref renderer provider missing {field_name}"
            )
        state, original_rows, local_rows, snapshot_player_count = (
            self._snapshot_state_rows(snapshot, field_name=field_name)
        )
        if snapshot_player_count not in (0, self.player_count):
            raise ReplayCompatibilityError(
                "compact scalar-ref renderer provider player count mismatch: "
                f"{snapshot_player_count} != {self.player_count}"
            )
        if original_rows.size <= 0:
            return original_rows, np.zeros(
                (0, self.player_count, 64, 64),
                dtype=np.uint8,
            )
        if bool((original_rows < 0).any()) or bool((original_rows >= self.batch_size).any()):
            raise ReplayCompatibilityError(
                "compact scalar-ref renderer provider rows are outside batch size"
            )
        row_indices = np.repeat(local_rows.astype(np.int64), self.player_count)
        controlled_players = np.tile(
            np.arange(self.player_count, dtype=np.int64),
            int(local_rows.shape[0]),
        )
        out = np.zeros((row_indices.shape[0], 1, 64, 64), dtype=np.uint8)
        result = self.renderer.render(
            SourceStateBatchedRenderRequest(
                state=state,
                row_indices=row_indices,
                controlled_players=controlled_players,
                out=out,
                device_only=False,
                synchronize_device=self.synchronize_device,
            )
        )
        frames = np.asarray(result.frames)
        if frames.shape != out.shape:
            raise ReplayCompatibilityError(
                "renderer returned frames with unexpected shape; "
                f"got {frames.shape}, expected {out.shape}"
            )
        if frames.dtype != np.uint8:
            raise ReplayCompatibilityError(f"renderer frames must be uint8, got {frames.dtype}")
        self.render_call_count += 1
        self.rendered_frame_count += int(frames.shape[0])
        latest = frames.reshape(original_rows.shape[0], self.player_count, 1, 64, 64)[:, :, 0]
        return original_rows, latest

    def _snapshot_state_rows(
        self,
        snapshot: Any,
        *,
        field_name: str,
    ) -> tuple[dict[str, np.ndarray], np.ndarray, np.ndarray, int]:
        from curvyzero.training.replay_chunk_v0 import ReplayCompatibilityError

        if isinstance(snapshot, CompactReplayRenderStateSnapshotV1):
            if str(snapshot.schema_id) != COMPACT_REPLAY_RENDER_STATE_SNAPSHOT_SCHEMA_ID:
                raise ReplayCompatibilityError(
                    f"compact scalar-ref renderer provider got bad {field_name} schema"
                )
            if str(snapshot.state_kind) != "row_sliced_render_state_v1":
                raise ReplayCompatibilityError(
                    f"compact scalar-ref renderer provider got bad {field_name} kind"
                )
            state = {str(key): np.asarray(value) for key, value in snapshot.state.items()}
            original_rows = np.asarray(snapshot.rows, dtype=np.int64).reshape(-1)
            local_rows = np.arange(original_rows.shape[0], dtype=np.int64)
            return state, original_rows, local_rows, int(snapshot.player_count)
        if not isinstance(snapshot, Mapping):
            raise ReplayCompatibilityError(
                f"compact scalar-ref renderer provider cannot consume {field_name}"
            )
        state = {str(key): np.asarray(value) for key, value in dict(snapshot).items()}
        row_count = _render_state_first_row_count(state)
        original_rows = np.arange(row_count, dtype=np.int64)
        return state, original_rows, original_rows.copy(), 0

    def _write_latest_frames(self, rows: np.ndarray, latest: np.ndarray) -> None:
        if self.stack_storage_dtype == HYBRID_STACK_STORAGE_DTYPE_FLOAT32:
            self._stack[rows, :, -1] = latest.astype(np.float32) * np.float32(
                1.0 / 255.0
            )
        else:
            self._stack[rows, :, -1] = latest

    def _done_rows_from_step(self, step: Any) -> np.ndarray:
        done = getattr(step, "done", None)
        if done is None:
            return np.asarray([], dtype=np.int64)
        done_array = np.asarray(done, dtype=np.bool_)
        if done_array.ndim == 0:
            if bool(done_array):
                return np.arange(self.batch_size, dtype=np.int64)
            return np.asarray([], dtype=np.int64)
        if done_array.shape[0] == self.batch_size:
            row_done = done_array.reshape(self.batch_size, -1).any(axis=1)
        elif done_array.size == self.batch_size:
            row_done = done_array.reshape(self.batch_size)
        else:
            raise ValueError(
                "done rows must have a leading dimension matching provider batch_size"
            )
        return np.flatnonzero(row_done).astype(np.int64, copy=False)

    def _step_with_observation(self, step: Any, observation: np.ndarray) -> Any:
        if step is None:
            raise ValueError("compact scalar-ref replay entry has no step")
        compact_batch = self._compact_batch_with_host_observation_source(
            getattr(step, "compact_batch", None)
        )
        return self._replace_step_fields(
            step,
            observation=_clone_compact_replay_store_value(observation),
            compact_batch=compact_batch,
        )

    def _compact_batch_with_host_observation_source(self, compact_batch: Any) -> Any:
        if compact_batch is None:
            return CompactReplayStoreCompactBatchSnapshotV1(
                final_observation=None,
                observation_source=COMPACT_OBSERVATION_SOURCE_HOST_ARRAY_V1,
            )
        if hasattr(compact_batch, "__dataclass_fields__"):
            return replace(
                compact_batch,
                observation_source=COMPACT_OBSERVATION_SOURCE_HOST_ARRAY_V1,
            )
        data = dict(vars(compact_batch)) if hasattr(compact_batch, "__dict__") else {}
        data["observation_source"] = COMPACT_OBSERVATION_SOURCE_HOST_ARRAY_V1
        return SimpleNamespace(**data)

    def _step_with_compact_final_observation(
        self,
        step: Any,
        final_observation: np.ndarray,
    ) -> Any:
        compact_batch = getattr(step, "compact_batch", None)
        final_copy = _clone_compact_replay_store_value(final_observation)
        if compact_batch is None:
            compact_batch = CompactReplayStoreCompactBatchSnapshotV1(
                final_observation=final_copy,
                observation_source=COMPACT_OBSERVATION_SOURCE_HOST_ARRAY_V1,
            )
        elif hasattr(compact_batch, "__dataclass_fields__"):
            compact_batch = replace(
                compact_batch,
                final_observation=final_copy,
                observation_source=COMPACT_OBSERVATION_SOURCE_HOST_ARRAY_V1,
            )
        else:
            data = dict(vars(compact_batch)) if hasattr(compact_batch, "__dict__") else {}
            data.update(
                {
                    "final_observation": final_copy,
                    "observation_source": COMPACT_OBSERVATION_SOURCE_HOST_ARRAY_V1,
                }
            )
            compact_batch = SimpleNamespace(**data)
        return self._replace_step_fields(step, compact_batch=compact_batch)

    def _replace_step_fields(self, step: Any, **updates: Any) -> Any:
        if hasattr(step, "__dataclass_fields__"):
            return replace(step, **updates)
        data = dict(vars(step)) if hasattr(step, "__dict__") else {}
        data.update(updates)
        return SimpleNamespace(**data)


