@dataclass(frozen=True, slots=True)
class HybridCompactBatch:
    """Pre-scalar row/player batch for replay/search/RND-shaped probes."""

    observation: np.ndarray
    action_mask: np.ndarray
    reward: np.ndarray
    final_reward_map: np.ndarray
    done: np.ndarray
    policy_env_id: np.ndarray
    policy_env_row: np.ndarray
    policy_player: np.ndarray
    target_reward: np.ndarray
    done_root: np.ndarray
    to_play: np.ndarray
    active_root_mask: np.ndarray
    final_observation: np.ndarray | None
    final_observation_row_mask: np.ndarray
    terminal_row_mask: np.ndarray
    autoreset_row_mask: np.ndarray
    terminal_global_rows: np.ndarray
    autoreset_global_rows: np.ndarray
    episode_step: np.ndarray
    elapsed_ms: np.ndarray
    round_id: np.ndarray
    alive: np.ndarray
    joint_action: np.ndarray
    terminated: np.ndarray | None = None
    truncated: np.ndarray | None = None
    terminal_reason: np.ndarray | None = None
    death_count: np.ndarray | None = None
    death_player: np.ndarray | None = None
    death_cause: np.ndarray | None = None
    death_hit_owner: np.ndarray | None = None
    winner: np.ndarray | None = None
    draw: np.ndarray | None = None
    resident_observation: Any | None = None
    observation_source: str = COMPACT_OBSERVATION_SOURCE_HOST_ARRAY_V1

    def __post_init__(self) -> None:
        done = np.asarray(self.done, dtype=np.bool_)
        batch_size = int(done.shape[0])
        reward = np.asarray(self.reward)
        if reward.ndim >= 2:
            player_count = int(reward.shape[1])
        else:
            action_mask = np.asarray(self.action_mask)
            player_count = int(action_mask.shape[1]) if action_mask.ndim >= 2 else 1

        scalar_defaults: tuple[tuple[str, np.ndarray, Any], ...] = (
            ("terminated", done.copy(), np.bool_),
            ("truncated", np.zeros(batch_size, dtype=np.bool_), np.bool_),
            ("terminal_reason", np.zeros(batch_size, dtype=np.int16), np.int16),
            ("death_count", np.zeros(batch_size, dtype=np.int32), np.int32),
            ("winner", np.full(batch_size, -1, dtype=np.int16), np.int16),
            ("draw", np.zeros(batch_size, dtype=np.bool_), np.bool_),
        )
        for name, default, dtype in scalar_defaults:
            value = getattr(self, name)
            array = default if value is None else np.asarray(value, dtype=dtype)
            object.__setattr__(self, name, array)

        per_player_defaults: tuple[tuple[str, np.ndarray, Any], ...] = (
            (
                "death_player",
                np.full((batch_size, player_count), -1, dtype=np.int16),
                np.int16,
            ),
            (
                "death_cause",
                np.zeros((batch_size, player_count), dtype=np.int16),
                np.int16,
            ),
            (
                "death_hit_owner",
                np.full((batch_size, player_count), -1, dtype=np.int16),
                np.int16,
            ),
        )
        for name, default, dtype in per_player_defaults:
            value = getattr(self, name)
            array = default if value is None else np.asarray(value, dtype=dtype)
            object.__setattr__(self, name, array)


