def _joint_action_checksum(joint_action: np.ndarray) -> int:
    action = np.asarray(joint_action, dtype=np.int64).reshape(-1)
    if action.size == 0:
        return 0
    weights = np.arange(1, action.size + 1, dtype=np.int64)
    return int(action.dot(weights))


def _bool_array_checksum(value: np.ndarray) -> int:
    array = np.asarray(value, dtype=np.int64).reshape(-1)
    if array.size == 0:
        return 0
    weights = np.arange(1, array.size + 1, dtype=np.int64)
    return int(array.dot(weights))


def _int_array_checksum(value: Any) -> int:
    array = np.asarray(value, dtype=np.int64).reshape(-1)
    if array.size == 0:
        return 0
    weights = np.arange(1, array.size + 1, dtype=np.int64)
    return int(array.dot(weights))


def _ragged_i64_checksum(value: list[list[int]]) -> int:
    flattened = [int(item) for row in value for item in row]
    return _int_array_checksum(flattened)


def _float_array_checksum(value: np.ndarray) -> int:
    array = np.rint(np.asarray(value, dtype=np.float64).reshape(-1) * 1_000_000.0).astype(
        np.int64,
        copy=False,
    )
    if array.size == 0:
        return 0
    weights = np.arange(1, array.size + 1, dtype=np.int64)
    return int(array.dot(weights))


def _allocate_compact_payload_buffers(
    *,
    batch_size: int,
    player_count: int,
) -> dict[str, np.ndarray]:
    return {
        "global_rows": np.arange(batch_size, dtype=np.int32),
        "reward": np.zeros((batch_size, player_count), dtype=np.float32),
        "final_reward_map": np.zeros((batch_size, player_count), dtype=np.float32),
        "done": np.zeros(batch_size, dtype=np.bool_),
        "terminated": np.zeros(batch_size, dtype=np.bool_),
        "truncated": np.zeros(batch_size, dtype=np.bool_),
        "terminal_reason": np.zeros(batch_size, dtype=np.int16),
        "death_count": np.zeros(batch_size, dtype=np.int32),
        "death_player": np.full((batch_size, player_count), -1, dtype=np.int16),
        "death_cause": np.zeros((batch_size, player_count), dtype=np.int16),
        "death_hit_owner": np.full((batch_size, player_count), -1, dtype=np.int16),
        "winner": np.full(batch_size, -1, dtype=np.int16),
        "draw": np.zeros(batch_size, dtype=np.bool_),
        "episode_step": np.zeros(batch_size, dtype=np.int32),
        "elapsed_ms": np.zeros(batch_size, dtype=np.float64),
        "round_id": np.zeros(batch_size, dtype=np.int32),
        "alive": np.zeros((batch_size, player_count), dtype=np.bool_),
        "action_mask": np.zeros((batch_size, player_count, ACTION_COUNT), dtype=np.bool_),
        "joint_action": np.zeros((batch_size, player_count), dtype=np.int16),
        "terminal_global_rows": np.asarray([], dtype=np.int32),
        "autoreset_global_rows": np.asarray([], dtype=np.int32),
    }


def _copy_compact_payload_for_step(payload: dict[str, np.ndarray]) -> dict[str, np.ndarray]:
    return {str(key): np.asarray(value).copy() for key, value in payload.items()}


_OWNER_MINIMAL_COMPACT_STEP_PAYLOAD_KEYS = (
    "global_rows",
    "episode_step",
    "terminal_global_rows",
    "autoreset_global_rows",
    "joint_action",
    "compact_profile_autoreset_direct_count",
    "compact_profile_autoreset_template_copy_skipped_count",
    "compact_profile_autoreset_direct_row_count",
)


def _copy_minimal_compact_payload_for_owner_step(
    payload: dict[str, np.ndarray],
) -> dict[str, np.ndarray]:
    return {
        str(key): np.asarray(payload[key]).copy()
        for key in _OWNER_MINIMAL_COMPACT_STEP_PAYLOAD_KEYS
        if key in payload
    }


def _compact_payload_snapshot_nbytes(payload: Mapping[str, Any]) -> int:
    total = 0
    for value in payload.values():
        try:
            total += int(np.asarray(value).nbytes)
        except (TypeError, ValueError):
            total += 0
    return int(total)


def _make_compact_owner_mechanics_step_frame_ring(
    *, batch_size: int, player_count: int
) -> dict[str, np.ndarray]:
    slot_count = COMPACT_OWNER_MECHANICS_STEP_FRAME_HANDLE_RING_SLOT_COUNT
    root_count = int(batch_size) * int(player_count)
    return {
        "slot_generation": np.full((slot_count,), -1, dtype=np.int64),
        "action_mask": np.empty(
            (slot_count, int(batch_size), int(player_count), ACTION_COUNT),
            dtype=np.bool_,
        ),
        "reward": np.empty((slot_count, int(batch_size), int(player_count)), dtype=np.float32),
        "final_reward_map": np.empty(
            (slot_count, int(batch_size), int(player_count)),
            dtype=np.float32,
        ),
        "done": np.empty((slot_count, int(batch_size)), dtype=np.bool_),
        "policy_env_id": np.empty((slot_count, root_count), dtype=np.int32),
        "policy_env_row": np.empty((slot_count, root_count), dtype=np.int32),
        "policy_player": np.empty((slot_count, root_count), dtype=np.int32),
        "target_reward": np.empty((slot_count, root_count, 1), dtype=np.float32),
        "done_root": np.empty((slot_count, root_count), dtype=np.bool_),
        "to_play": np.empty((slot_count, root_count), dtype=np.int64),
        "active_root_mask": np.empty((slot_count, root_count), dtype=np.bool_),
        "final_observation_row_mask": np.empty(
            (slot_count, int(batch_size)),
            dtype=np.bool_,
        ),
        "terminal_row_mask": np.empty((slot_count, int(batch_size)), dtype=np.bool_),
        "autoreset_row_mask": np.empty((slot_count, int(batch_size)), dtype=np.bool_),
        "episode_step": np.empty((slot_count, int(batch_size)), dtype=np.int32),
        "elapsed_ms": np.empty((slot_count, int(batch_size)), dtype=np.float64),
        "round_id": np.empty((slot_count, int(batch_size)), dtype=np.int32),
        "alive": np.empty((slot_count, int(batch_size), int(player_count)), dtype=np.bool_),
        "joint_action": np.empty(
            (slot_count, int(batch_size), int(player_count)),
            dtype=np.int16,
        ),
        "terminated": np.empty((slot_count, int(batch_size)), dtype=np.bool_),
        "truncated": np.empty((slot_count, int(batch_size)), dtype=np.bool_),
        "terminal_reason": np.empty((slot_count, int(batch_size)), dtype=np.int16),
        "death_count": np.empty((slot_count, int(batch_size)), dtype=np.int32),
        "death_player": np.empty(
            (slot_count, int(batch_size), int(player_count)),
            dtype=np.int16,
        ),
        "death_cause": np.empty(
            (slot_count, int(batch_size), int(player_count)),
            dtype=np.int16,
        ),
        "death_hit_owner": np.empty(
            (slot_count, int(batch_size), int(player_count)),
            dtype=np.int16,
        ),
        "winner": np.empty((slot_count, int(batch_size)), dtype=np.int16),
        "draw": np.empty((slot_count, int(batch_size)), dtype=np.bool_),
    }


def _publish_compact_owner_mechanics_step_frame_slot(
    *,
    ring: dict[str, np.ndarray],
    action_mask: np.ndarray,
    reward: np.ndarray,
    final_reward_map: np.ndarray,
    done: np.ndarray,
    policy_env_id: np.ndarray,
    policy_env_row: np.ndarray,
    policy_player: np.ndarray,
    terminal_global_rows: np.ndarray,
    autoreset_global_rows: np.ndarray,
    episode_step: np.ndarray,
    elapsed_ms: np.ndarray,
    round_id: np.ndarray,
    alive: np.ndarray,
    joint_action: np.ndarray,
    batch_size: int,
    terminated: np.ndarray,
    truncated: np.ndarray,
    terminal_reason: np.ndarray,
    death_count: np.ndarray,
    death_player: np.ndarray,
    death_cause: np.ndarray,
    death_hit_owner: np.ndarray,
    winner: np.ndarray,
    draw: np.ndarray,
    resident_observation: Any,
    step_frame_slot_id: int,
    step_frame_generation: int,
) -> CompactOwnerMechanicsStepFrameSlotV1:
    slot_id = int(step_frame_slot_id)
    batch_size_int = int(batch_size)
    player_count = int(np.asarray(joint_action, dtype=np.int16).reshape(batch_size_int, -1).shape[1])
    root_count = batch_size_int * player_count

    ring["slot_generation"][slot_id] = int(step_frame_generation)
    ring["action_mask"][slot_id][...] = np.asarray(action_mask, dtype=np.bool_)
    ring["reward"][slot_id][...] = np.asarray(reward, dtype=np.float32)
    ring["final_reward_map"][slot_id][...] = np.asarray(final_reward_map, dtype=np.float32)
    ring["done"][slot_id][...] = np.asarray(done, dtype=np.bool_)
    ring["policy_env_id"][slot_id][...] = np.asarray(policy_env_id, dtype=np.int32)
    ring["policy_env_row"][slot_id][...] = np.asarray(policy_env_row, dtype=np.int32)
    ring["policy_player"][slot_id][...] = np.asarray(policy_player, dtype=np.int32)
    ring["target_reward"][slot_id][...] = ring["reward"][slot_id].reshape(root_count, 1)
    ring["done_root"][slot_id][...] = np.repeat(ring["done"][slot_id], player_count)
    ring["to_play"][slot_id].fill(-1)
    ring["active_root_mask"][slot_id][...] = np.logical_and(
        ~ring["done_root"][slot_id],
        ring["action_mask"][slot_id].reshape(root_count, ACTION_COUNT).any(axis=1),
    )
    ring["final_observation_row_mask"][slot_id][...] = (
        ring["done"][slot_id]
        if _resident_final_observation_storage_present(resident_observation)
        else np.zeros(batch_size_int, dtype=np.bool_)
    )
    ring["terminal_row_mask"][slot_id][...] = _row_mask_from_rows(
        terminal_global_rows,
        batch_size=batch_size_int,
    )
    ring["autoreset_row_mask"][slot_id][...] = _row_mask_from_rows(
        autoreset_global_rows,
        batch_size=batch_size_int,
    )
    ring["episode_step"][slot_id][...] = np.asarray(episode_step, dtype=np.int32)
    ring["elapsed_ms"][slot_id][...] = np.asarray(elapsed_ms, dtype=np.float64)
    ring["round_id"][slot_id][...] = np.asarray(round_id, dtype=np.int32)
    ring["alive"][slot_id][...] = np.asarray(alive, dtype=np.bool_)
    ring["joint_action"][slot_id][...] = np.asarray(joint_action, dtype=np.int16)
    ring["terminated"][slot_id][...] = np.asarray(terminated, dtype=np.bool_)
    ring["truncated"][slot_id][...] = np.asarray(truncated, dtype=np.bool_)
    ring["terminal_reason"][slot_id][...] = np.asarray(terminal_reason, dtype=np.int16)
    ring["death_count"][slot_id][...] = np.asarray(death_count, dtype=np.int32)
    ring["death_player"][slot_id][...] = np.asarray(death_player, dtype=np.int16)
    ring["death_cause"][slot_id][...] = np.asarray(death_cause, dtype=np.int16)
    ring["death_hit_owner"][slot_id][...] = np.asarray(death_hit_owner, dtype=np.int16)
    ring["winner"][slot_id][...] = np.asarray(winner, dtype=np.int16)
    ring["draw"][slot_id][...] = np.asarray(draw, dtype=np.bool_)

    step_frame_digest = _compact_owner_mechanics_step_frame_digest_v1(
        action_mask=ring["action_mask"][slot_id],
        reward=ring["reward"][slot_id],
        done=ring["done"][slot_id],
        policy_env_row=ring["policy_env_row"][slot_id],
        policy_player=ring["policy_player"][slot_id],
        joint_action=ring["joint_action"][slot_id],
        terminated=ring["terminated"][slot_id],
        truncated=ring["truncated"][slot_id],
        terminal_reason=ring["terminal_reason"][slot_id],
        episode_step=ring["episode_step"][slot_id],
        round_id=ring["round_id"][slot_id],
    )
    step_frame_handle = CompactOwnerMechanicsStepFrameHandleV1(
        schema_id=COMPACT_OWNER_MECHANICS_STEP_FRAME_HANDLE_SCHEMA_ID,
        slot_id=slot_id,
        generation=int(step_frame_generation),
        digest=str(step_frame_digest),
        batch_size=batch_size_int,
        player_count=player_count,
        resident_observation_handle_present=True,
    )
    metadata = {
        "compact_owner_mechanics_step_boundary": True,
        "compact_owner_mechanics_step_view_schema_id": "",
        "compact_owner_mechanics_step_frame_slot_schema_id": (
            COMPACT_OWNER_MECHANICS_STEP_FRAME_SLOT_SCHEMA_ID
        ),
        "compact_owner_mechanics_step_frame_handle_schema_id": (
            COMPACT_OWNER_MECHANICS_STEP_FRAME_HANDLE_SCHEMA_ID
        ),
        "compact_owner_mechanics_step_frame_handle_ring_used": True,
        "compact_owner_mechanics_step_frame_handle_published": True,
        "compact_owner_mechanics_step_frame_handle_ring_slot_count": (
            COMPACT_OWNER_MECHANICS_STEP_FRAME_HANDLE_RING_SLOT_COUNT
        ),
        "compact_owner_mechanics_step_frame_handle_slot_id": slot_id,
        "compact_owner_mechanics_step_frame_handle_generation": int(
            step_frame_generation
        ),
        "compact_owner_mechanics_step_frame_handle_digest": str(step_frame_digest),
        "compact_owner_mechanics_step_frame_handle_digest_verified": True,
        "compact_owner_mechanics_step_frame_handle_publish_count": 1,
        "compact_owner_mechanics_step_frame_slot_write_count": 1,
        "compact_owner_mechanics_step_boundary_count": 1,
        "compact_owner_mechanics_parent_step_frame_build_count": 0,
        "compact_owner_mechanics_parent_compact_batch_builder_call_count": 0,
        "compact_owner_mechanics_parent_compact_batch_object_count": 0,
        "compact_owner_mechanics_parent_compact_batch_builder_used": False,
        "compact_owner_mechanics_step_view_object_count": 0,
        "compact_owner_mechanics_host_observation_bytes_sent": 0,
        "compact_owner_mechanics_host_final_observation_bytes_sent": 0,
        "compact_owner_mechanics_resident_observation_handle_present": True,
        "compact_owner_mechanics_direct_root_build_request_required": True,
    }
    return CompactOwnerMechanicsStepFrameSlotV1(
        schema_id=COMPACT_OWNER_MECHANICS_STEP_FRAME_SLOT_SCHEMA_ID,
        step_frame_handle=step_frame_handle,
        slot_generation=ring["slot_generation"][slot_id : slot_id + 1],
        metadata=metadata,
        observation=None,
        action_mask=ring["action_mask"][slot_id],
        reward=ring["reward"][slot_id],
        final_reward_map=ring["final_reward_map"][slot_id],
        done=ring["done"][slot_id],
        policy_env_id=ring["policy_env_id"][slot_id],
        policy_env_row=ring["policy_env_row"][slot_id],
        policy_player=ring["policy_player"][slot_id],
        target_reward=ring["target_reward"][slot_id],
        done_root=ring["done_root"][slot_id],
        to_play=ring["to_play"][slot_id],
        active_root_mask=ring["active_root_mask"][slot_id],
        final_observation=None,
        final_observation_row_mask=ring["final_observation_row_mask"][slot_id],
        terminal_row_mask=ring["terminal_row_mask"][slot_id],
        autoreset_row_mask=ring["autoreset_row_mask"][slot_id],
        terminal_global_rows=np.asarray(terminal_global_rows, dtype=np.int32),
        autoreset_global_rows=np.asarray(autoreset_global_rows, dtype=np.int32),
        episode_step=ring["episode_step"][slot_id],
        elapsed_ms=ring["elapsed_ms"][slot_id],
        round_id=ring["round_id"][slot_id],
        alive=ring["alive"][slot_id],
        joint_action=ring["joint_action"][slot_id],
        terminated=ring["terminated"][slot_id],
        truncated=ring["truncated"][slot_id],
        terminal_reason=ring["terminal_reason"][slot_id],
        death_count=ring["death_count"][slot_id],
        death_player=ring["death_player"][slot_id],
        death_cause=ring["death_cause"][slot_id],
        death_hit_owner=ring["death_hit_owner"][slot_id],
        winner=ring["winner"][slot_id],
        draw=ring["draw"][slot_id],
        resident_observation=resident_observation,
        observation_source=COMPACT_OBSERVATION_SOURCE_RESIDENT_DEVICE_V1,
    )


