def _refresh_compact_rollout_slab_search_from_learner(
    *,
    compact_rollout_slab: Any,
    learner_probe: Any,
    policy_version_ref: str,
    model_version_ref: str,
    policy_source: str,
    learner_update_count: int,
    learner_model_state_dict: Mapping[str, Any] | None = None,
    expected_model_state_digest: str | None = None,
) -> dict[str, Any]:
    if compact_rollout_slab is None:
        raise ValueError("search refresh after learner gate requires compact_rollout_slab")
    search_service = getattr(compact_rollout_slab, "search_service", None)
    if search_service is None:
        raise ValueError("search refresh after learner gate requires search service")
    refresh_model_state = getattr(search_service, "refresh_model_state", None)
    if not callable(refresh_model_state):
        raise ValueError(
            "search refresh after learner gate requires search_service.refresh_model_state"
        )
    object_id_fn = getattr(learner_probe, "model_object_id", None)
    if learner_model_state_dict is None:
        state_dict_fn = getattr(learner_probe, "model_state_dict", None)
    else:
        state_dict_fn = None
    if (learner_model_state_dict is None and not callable(state_dict_fn)) or not callable(
        object_id_fn
    ):
        raise ValueError("search refresh after learner gate requires a model-backed learner")
    learner_object_id = int(object_id_fn())
    refresh_kwargs = {
        "model_state_dict": (
            dict(learner_model_state_dict)
            if learner_model_state_dict is not None
            else state_dict_fn()
        ),
        "policy_version_ref": str(policy_version_ref),
        "model_version_ref": str(model_version_ref),
        "policy_source": str(policy_source),
        "learner_update_count": int(learner_update_count),
    }
    if expected_model_state_digest is not None:
        refresh_kwargs["expected_model_state_digest"] = expected_model_state_digest
    search_worker_state = refresh_model_state(**refresh_kwargs)
    if not isinstance(search_worker_state, Mapping):
        raise ValueError("search refresh after learner gate returned non-mapping state")
    search_worker_model_object_id = int(search_worker_state.get("search_worker_model_object_id", 0))
    if search_worker_model_object_id <= 0:
        raise ValueError("search refresh after learner gate missing search model object id")
    if search_worker_model_object_id == learner_object_id:
        raise ValueError("search refresh after learner gate requires distinct search model")
    refreshed_update_count = int(search_worker_state.get("learner_update_count", 0))
    if refreshed_update_count != int(learner_update_count):
        raise ValueError("search refresh after learner gate update count mismatch")
    refreshed_digest = str(search_worker_state.get("model_state_digest", "")).strip()
    if not refreshed_digest:
        raise ValueError("search refresh after learner gate missing refreshed digest")
    return {
        "search_worker_state": dict(search_worker_state),
        "learner_update_count": int(learner_update_count),
        "model_state_digest": refreshed_digest,
        "learner_model_object_id": learner_object_id,
        "search_worker_model_object_id": search_worker_model_object_id,
        "search_worker_distinct_from_learner": True,
    }


def _refresh_compact_rollout_slab_search_from_owner_ref(
    *,
    compact_rollout_slab: Any,
    owner_ref: Mapping[str, Any],
    policy_version_ref: str,
    model_version_ref: str,
    policy_source: str,
    learner_update_count: int,
    expected_model_state_digest: str | None = None,
) -> dict[str, Any]:
    """Refresh search from a persistent owner-published model reference."""

    if compact_rollout_slab is None:
        raise ValueError("owner-ref search refresh requires compact_rollout_slab")
    search_service = getattr(compact_rollout_slab, "search_service", None)
    if search_service is None:
        raise ValueError("owner-ref search refresh requires search service")
    refresh_owner_ref = getattr(search_service, "refresh_model_owner_ref", None)
    if not callable(refresh_owner_ref):
        raise ValueError(
            "owner-ref search refresh requires search_service.refresh_model_owner_ref"
        )
    owner_ref_dict = dict(owner_ref)
    if owner_ref_dict.get("transport_kind") != COMPACT_MODEL_STATE_TRANSPORT_OWNER_REF_V1:
        raise ValueError("owner-ref search refresh received wrong transport kind")
    policy_ref = str(policy_version_ref).strip()
    model_ref = str(model_version_ref).strip()
    source = str(policy_source).strip()
    update_count = int(learner_update_count)
    if not policy_ref:
        raise ValueError("policy_version_ref must be non-empty")
    if not model_ref:
        raise ValueError("model_version_ref must be non-empty")
    if not source:
        raise ValueError("policy_source must be non-empty")
    if update_count <= 0:
        raise ValueError("learner_update_count must be positive")
    expected_digest = (
        str(expected_model_state_digest).strip()
        if expected_model_state_digest is not None
        else str(owner_ref_dict.get("model_state_digest") or "").strip()
    )
    search_worker_state = refresh_owner_ref(
        owner_ref=owner_ref_dict,
        policy_version_ref=policy_ref,
        model_version_ref=model_ref,
        policy_source=source,
        learner_update_count=update_count,
        expected_model_state_digest=(expected_digest or None),
    )
    if not isinstance(search_worker_state, Mapping):
        raise ValueError("owner-ref search refresh returned non-mapping state")
    search_worker_model_object_id = int(search_worker_state.get("search_worker_model_object_id", 0))
    if search_worker_model_object_id <= 0:
        raise ValueError("owner-ref search refresh missing search model object id")
    refreshed_update_count = int(search_worker_state.get("learner_update_count", 0))
    if refreshed_update_count != update_count:
        raise ValueError("owner-ref search refresh update count mismatch")
    refreshed_digest = str(search_worker_state.get("model_state_digest", "")).strip()
    if not refreshed_digest:
        raise ValueError("owner-ref search refresh missing refreshed digest")
    if expected_digest and refreshed_digest != expected_digest:
        raise ValueError("owner-ref search refresh model digest mismatch")
    return {
        "search_worker_state": dict(search_worker_state),
        "learner_update_count": update_count,
        "model_state_digest": refreshed_digest,
        "learner_model_object_id": int(owner_ref_dict.get("model_object_id") or 0),
        "search_worker_model_object_id": search_worker_model_object_id,
        "search_worker_distinct_from_learner": True,
    }


def _two_record_replay_chunk_from_hybrid_steps(
    previous_step: HybridObservationProfileStep,
    current_step: HybridObservationProfileStep,
):
    recorder = SourceStateMultiplayerTrainerReplayRecorder()
    recorder.record(_trainer_replay_step_from_hybrid_step(previous_step))
    recorder.record(_trainer_replay_step_from_hybrid_step(current_step))
    return recorder.build_chunk()


def _compact_terminal_metadata_from_step(
    step: HybridObservationProfileStep,
) -> dict[str, Any]:
    """Small JSON-safe terminal/death summary for compact replay metadata."""

    done = np.asarray(step.done, dtype=np.bool_)
    terminated = np.asarray(step.terminated, dtype=np.bool_)
    truncated = np.asarray(step.truncated, dtype=np.bool_)
    death_count = np.asarray(step.death_count, dtype=np.int32)
    terminal_reason = np.asarray(step.terminal_reason, dtype=np.int16)
    terminal_rows = done.reshape(-1)
    death_rows = death_count.reshape(-1) > 0
    return {
        "next_done_row_count": int(done.sum()),
        "next_terminated_row_count": int(terminated.sum()),
        "next_truncated_row_count": int(truncated.sum()),
        "next_death_row_count": int(death_rows.sum()),
        "next_death_count_total": int(death_count.sum()),
        "next_terminal_reason": terminal_reason.tolist(),
        "next_death_count": death_count.tolist(),
        "next_death_player": np.asarray(step.death_player, dtype=np.int16).tolist(),
        "next_death_cause": np.asarray(step.death_cause, dtype=np.int16).tolist(),
        "next_death_hit_owner": np.asarray(
            step.death_hit_owner,
            dtype=np.int16,
        ).tolist(),
        "next_winner": np.asarray(step.winner, dtype=np.int16).tolist(),
        "next_draw": np.asarray(step.draw, dtype=np.bool_).tolist(),
        "next_terminal_rows": np.flatnonzero(terminal_rows).astype(np.int32).tolist(),
    }


def _trainer_replay_step_from_hybrid_step(
    step: HybridObservationProfileStep,
) -> MultiplayerTrainerStepV0:
    observation = np.asarray(step.observation, dtype=np.float32).copy()
    action_mask = np.asarray(step.action_mask, dtype=np.bool_).copy()
    live_mask = np.asarray(step.payload.get("alive"), dtype=np.bool_).copy()
    env_row, player = np.nonzero(live_mask)
    env_row = env_row.astype(np.int32, copy=False)
    player = player.astype(np.int16, copy=False)
    final_row_mask = np.asarray(step.done, dtype=np.bool_).copy()
    final_observation = np.asarray(step.observation, dtype=np.float32).copy()
    final_reward_map = np.asarray(step.final_reward_map, dtype=np.float32).copy()
    return MultiplayerTrainerStepV0(
        observation=observation,
        legal_action_mask=action_mask,
        lightzero_action_mask=action_mask.copy(),
        live_mask=live_mask,
        policy_observation=observation[env_row, player].copy(),
        policy_action_mask=action_mask[env_row, player].copy(),
        policy_env_row=env_row.copy(),
        policy_player=player.copy(),
        joint_action=np.asarray(step.payload["joint_action"], dtype=np.int16).copy(),
        reward=np.asarray(step.reward, dtype=np.float32).copy(),
        done=np.asarray(step.done, dtype=np.bool_).copy(),
        terminated=np.asarray(step.terminated, dtype=np.bool_).copy(),
        truncated=np.asarray(step.truncated, dtype=np.bool_).copy(),
        final_observation=final_observation,
        final_observation_row_mask=final_row_mask,
        final_reward_map=final_reward_map,
        info={
            "trainer_surface_api": "hybrid_profile_compact_service_replay_proof",
            "observation_schema_id": "hybrid_profile_observation",
            "reward_schema_id": "hybrid_profile_reward",
            "reward_variant": "profile",
            "trail_render_mode": "profile",
            "bonus_render_mode": "profile",
            "terminal_reason": np.asarray(step.terminal_reason, dtype=np.int16).copy(),
            "death_count": np.asarray(step.death_count, dtype=np.int32).copy(),
            "death_player": np.asarray(step.death_player, dtype=np.int16).copy(),
            "death_cause": np.asarray(step.death_cause, dtype=np.int16).copy(),
            "death_hit_owner": np.asarray(step.death_hit_owner, dtype=np.int16).copy(),
            "winner": np.asarray(step.winner, dtype=np.int16).copy(),
            "draw": np.asarray(step.draw, dtype=np.bool_).copy(),
        },
    )


def _merge_payloads(
    payloads: list[HybridActorStepPayload],
    *,
    batch_size: int,
    player_count: int,
) -> dict[str, np.ndarray]:
    reward = np.zeros((batch_size, player_count), dtype=np.float32)
    final_reward_map = np.zeros((batch_size, player_count), dtype=np.float32)
    done = np.zeros(batch_size, dtype=np.bool_)
    terminated = np.zeros(batch_size, dtype=np.bool_)
    truncated = np.zeros(batch_size, dtype=np.bool_)
    terminal_reason = np.zeros(batch_size, dtype=np.int16)
    death_count = np.zeros(batch_size, dtype=np.int32)
    death_player = np.full((batch_size, player_count), -1, dtype=np.int16)
    death_cause = np.zeros((batch_size, player_count), dtype=np.int16)
    death_hit_owner = np.full((batch_size, player_count), -1, dtype=np.int16)
    winner = np.full(batch_size, -1, dtype=np.int16)
    draw = np.zeros(batch_size, dtype=np.bool_)
    episode_step = np.zeros(batch_size, dtype=np.int32)
    elapsed_ms = np.zeros(batch_size, dtype=np.float64)
    round_id = np.zeros(batch_size, dtype=np.int32)
    alive = np.zeros((batch_size, player_count), dtype=np.bool_)
    action_mask = np.zeros((batch_size, player_count, ACTION_COUNT), dtype=np.bool_)
    joint_action = np.zeros((batch_size, player_count), dtype=np.int16)
    global_rows_seen: list[np.ndarray] = []
    terminal_rows: list[np.ndarray] = []
    autoreset_rows: list[np.ndarray] = []

    for payload in payloads:
        rows = np.asarray(payload.global_rows, dtype=np.int32)
        global_rows_seen.append(rows.copy())
        reward[rows] = np.asarray(payload.reward, dtype=np.float32)
        final_reward_map[rows] = np.asarray(payload.final_reward_map, dtype=np.float32)
        done[rows] = np.asarray(payload.done, dtype=np.bool_)
        terminated[rows] = np.asarray(payload.terminated, dtype=np.bool_)
        truncated[rows] = np.asarray(payload.truncated, dtype=np.bool_)
        terminal_reason[rows] = np.asarray(payload.terminal_reason, dtype=np.int16)
        death_count[rows] = np.asarray(payload.death_count, dtype=np.int32)
        death_player[rows] = np.asarray(payload.death_player, dtype=np.int16)
        death_cause[rows] = np.asarray(payload.death_cause, dtype=np.int16)
        death_hit_owner[rows] = np.asarray(payload.death_hit_owner, dtype=np.int16)
        winner[rows] = np.asarray(payload.winner, dtype=np.int16)
        draw[rows] = np.asarray(payload.draw, dtype=np.bool_)
        episode_step[rows] = np.asarray(payload.episode_step, dtype=np.int32)
        elapsed_ms[rows] = np.asarray(payload.elapsed_ms, dtype=np.float64)
        round_id[rows] = np.asarray(payload.round_id, dtype=np.int32)
        alive[rows] = np.asarray(payload.alive, dtype=np.bool_)
        action_mask[rows] = np.asarray(payload.action_mask, dtype=np.bool_)
        joint_action[rows] = np.asarray(payload.joint_action, dtype=np.int16)
        terminal_rows.append(np.asarray(payload.terminal_global_rows, dtype=np.int32))
        autoreset_rows.append(np.asarray(payload.autoreset_global_rows, dtype=np.int32))

    global_rows = (
        np.concatenate(global_rows_seen).astype(np.int32, copy=False)
        if global_rows_seen
        else np.asarray([], dtype=np.int32)
    )
    if global_rows.shape != (batch_size,) or not np.array_equal(
        np.sort(global_rows),
        np.arange(batch_size, dtype=np.int32),
    ):
        raise ValueError("actor payloads must cover each global row exactly once")

    return {
        "global_rows": np.arange(batch_size, dtype=np.int32),
        "reward": reward,
        "final_reward_map": final_reward_map,
        "done": done,
        "terminated": terminated,
        "truncated": truncated,
        "terminal_reason": terminal_reason,
        "death_count": death_count,
        "death_player": death_player,
        "death_cause": death_cause,
        "death_hit_owner": death_hit_owner,
        "winner": winner,
        "draw": draw,
        "episode_step": episode_step,
        "elapsed_ms": elapsed_ms,
        "round_id": round_id,
        "alive": alive,
        "action_mask": action_mask,
        "joint_action": joint_action,
        "terminal_global_rows": _concat_int32(terminal_rows),
        "autoreset_global_rows": _concat_int32(autoreset_rows),
    }


def _row_partitions(batch_size: int, actor_count: int) -> list[np.ndarray]:
    rows = np.arange(int(batch_size), dtype=np.int32)
    return [part.astype(np.int32, copy=True) for part in np.array_split(rows, int(actor_count))]


def _concat_int32(arrays: list[np.ndarray]) -> np.ndarray:
    non_empty = [np.asarray(array, dtype=np.int32).reshape(-1) for array in arrays if array.size]
    if not non_empty:
        return np.asarray([], dtype=np.int32)
    return np.concatenate(non_empty).astype(np.int32, copy=False)


def _render_state_keys_for_renderer(
    renderer: SourceStateBatchedObservationRenderer | None,
) -> frozenset[str] | None:
    if renderer is None:
        return None
    if str(renderer.backend_name) == PERSISTENT_GPU_PROFILE_RENDERER_BACKEND_NAME:
        return PERSISTENT_GPU_PROFILE_RENDER_STATE_KEYS
    return None


def _copy_render_state(
    state: Mapping[str, np.ndarray],
    *,
    keys: frozenset[str] | None = None,
) -> dict[str, np.ndarray]:
    if keys is None:
        return {str(key): np.asarray(value).copy() for key, value in state.items()}
    return {key: np.asarray(state[key]).copy() for key in keys if key in state}


def _copy_render_state_rows(
    state: Mapping[str, np.ndarray],
    *,
    rows: np.ndarray,
    keys: frozenset[str] | None = None,
) -> dict[str, np.ndarray]:
    row_indices = np.asarray(rows, dtype=np.int64).reshape(-1)
    if bool((row_indices < 0).any()):
        raise ValueError("render-state row snapshot rows must be nonnegative")
    state_items = (
        ((key, state[key]) for key in keys if key in state) if keys is not None else state.items()
    )
    snapshot: dict[str, np.ndarray] = {}
    for key, value in state_items:
        array = np.asarray(value)
        if array.ndim < 1:
            continue
        if bool((row_indices >= int(array.shape[0])).any()):
            raise ValueError(f"render-state row snapshot rows are out of range for {key!r}")
        snapshot[str(key)] = array[row_indices].copy()
    return snapshot


def _borrow_render_state(
    state: Mapping[str, np.ndarray],
    *,
    keys: frozenset[str] | None = None,
) -> dict[str, np.ndarray]:
    if keys is None:
        return {str(key): np.asarray(value) for key, value in state.items()}
    return {key: np.asarray(state[key]) for key in keys if key in state}


def _render_state_nbytes(state: Mapping[str, np.ndarray]) -> int:
    return int(sum(int(np.asarray(value).nbytes) for value in state.values()))


def _allocate_native_render_state_buffers(
    state: Mapping[str, np.ndarray],
    *,
    actor_row_count: int,
    batch_size: int,
    keys: frozenset[str] | None = None,
) -> dict[str, np.ndarray]:
    """Allocate parent-sized row buffers for renderer-backed native actor steps."""

    actor_rows = int(actor_row_count)
    if actor_rows < 1:
        raise ValueError("actor_row_count must be positive")
    buffers: dict[str, np.ndarray] = {}
    state_items = (
        ((key, state[key]) for key in keys if key in state) if keys is not None else state.items()
    )
    for key, value in state_items:
        array = np.asarray(value)
        if array.ndim >= 1 and array.shape[0] == actor_rows:
            buffers[str(key)] = _allocate_native_render_state_buffer(
                str(key),
                shape=(int(batch_size), *array.shape[1:]),
                dtype=array.dtype,
            )
        else:
            buffers[str(key)] = array.copy()
    return buffers


def _allocate_native_render_state_buffer(
    key: str,
    *,
    shape: tuple[int, ...],
    dtype: np.dtype[Any],
) -> np.ndarray:
    if key == "visual_trail_write_cursor":
        return np.full(shape, -1, dtype=dtype)
    if key == "visual_trail_owner":
        return np.full(shape, -1, dtype=dtype)
    if key in ("visual_trail_active", "visual_trail_break_before"):
        return np.zeros(shape, dtype=dtype)
    if key in ("visual_trail_pos", "visual_trail_radius"):
        return np.zeros(shape, dtype=dtype)
    return np.empty(shape, dtype=dtype)


def _allocate_persistent_compact_render_state_buffers(
    state: Mapping[str, np.ndarray],
    *,
    batch_size: int,
    player_count: int,
) -> dict[str, np.ndarray]:
    """Allocate parent-sized compact renderer buffers for the persistent GPU path."""

    if "visual_trail_pos" not in state or "visual_trail_active" not in state:
        raise ValueError("persistent compact render state requires visual trail arrays")
    trail_pos = np.asarray(state["visual_trail_pos"])
    if trail_pos.ndim != 3 or trail_pos.shape[2] != 2:
        raise ValueError("visual_trail_pos must have shape [B,S,2]")
    trail_slots = int(trail_pos.shape[1])
    if trail_slots < 1:
        raise ValueError("visual trail slot capacity must be positive")
    player_count_int = int(player_count)
    if player_count_int < 1:
        raise ValueError("player_count must be positive")
    bonus_active = state.get("bonus_active")
    bonus_count = 0 if bonus_active is None else int(np.asarray(bonus_active).shape[1])
    batch = int(batch_size)
    geometry_dtype = np.float32
    return {
        PERSISTENT_GPU_PROFILE_COMPACT_RENDER_STATE_MARKER: np.asarray(1, dtype=np.uint8),
        "trail_x": np.zeros((batch, trail_slots), dtype=geometry_dtype),
        "trail_y": np.zeros((batch, trail_slots), dtype=geometry_dtype),
        "trail_radius": np.zeros((batch, trail_slots), dtype=geometry_dtype),
        "trail_owner": np.full((batch, trail_slots), -1, dtype=np.int32),
        "trail_active": np.zeros((batch, trail_slots), dtype=np.uint8),
        "trail_break_before": np.zeros((batch, trail_slots), dtype=np.uint8),
        "trail_write_cursor": np.zeros((batch,), dtype=np.int32),
        "head_x": np.zeros((batch, player_count_int), dtype=geometry_dtype),
        "head_y": np.zeros((batch, player_count_int), dtype=geometry_dtype),
        "head_radius": np.zeros((batch, player_count_int), dtype=geometry_dtype),
        "head_alive": np.zeros((batch, player_count_int), dtype=np.uint8),
        "avatar_color": np.zeros((batch, player_count_int), dtype=np.int32),
        "bonus_x": np.zeros((batch, bonus_count), dtype=geometry_dtype),
        "bonus_y": np.zeros((batch, bonus_count), dtype=geometry_dtype),
        "bonus_radius": np.zeros((batch, bonus_count), dtype=geometry_dtype),
        "bonus_active": np.zeros((batch, bonus_count), dtype=np.uint8),
        "bonus_type": np.ones((batch, bonus_count), dtype=np.int32),
    }


def _write_native_render_state_rows(
    render_state: dict[str, np.ndarray],
    *,
    rows: np.ndarray,
    state: Mapping[str, np.ndarray],
) -> dict[str, float]:
    """Write an actor-local env state into parent-sized render buffers."""

    row_values = np.asarray(rows, dtype=np.int64).reshape(-1)
    timings = {field: 0.0 for field in _ACTOR_RENDER_STATE_WRITE_TIMING_FIELDS}
    incremental_visual_trail = _has_incremental_visual_trail_state(render_state, state)
    if incremental_visual_trail:
        started = time.perf_counter()
        _write_visual_trail_render_state_rows_incremental(
            render_state,
            rows=row_values,
            state=state,
        )
        timings["actor_render_state_write_visual_trail_sec"] += _elapsed(started)
    for key, destination in list(render_state.items()):
        if incremental_visual_trail and key in _RENDER_STATE_VISUAL_TRAIL_KEYS:
            continue
        if key not in state:
            continue
        started = time.perf_counter()
        source = np.asarray(state[key])
        if source.ndim >= 1 and source.shape[0] == row_values.shape[0]:
            row_slice = _contiguous_row_slice(row_values, limit=destination.shape[0])
            if row_slice is None:
                destination[row_values] = source
            else:
                destination[row_slice] = source
        elif destination.shape == source.shape:
            destination[...] = source
        else:
            render_state[str(key)] = source.copy()
        timings[_render_state_write_timing_field(key)] += _elapsed(started)
    return timings


def _has_incremental_visual_trail_state(
    render_state: Mapping[str, np.ndarray],
    state: Mapping[str, np.ndarray],
) -> bool:
    return all(key in render_state and key in state for key in _RENDER_STATE_VISUAL_TRAIL_KEYS)


def _write_visual_trail_render_state_rows_incremental(
    render_state: dict[str, np.ndarray],
    *,
    rows: np.ndarray,
    state: Mapping[str, np.ndarray],
) -> None:
    row_values = np.asarray(rows, dtype=np.int64).reshape(-1)
    if row_values.size == 0:
        return
    destination_cursor = np.asarray(render_state["visual_trail_write_cursor"])
    source_cursor = np.asarray(state["visual_trail_write_cursor"], dtype=np.int64)
    capacity = int(np.asarray(render_state["visual_trail_active"]).shape[1])
    for local_index, global_row_raw in enumerate(row_values):
        global_row = int(global_row_raw)
        new_cursor = int(np.clip(int(source_cursor[local_index]), 0, capacity))
        old_cursor = int(destination_cursor[global_row])
        full_copy = old_cursor < 0 or old_cursor > new_cursor or old_cursor > capacity
        if full_copy:
            for key in _RENDER_STATE_VISUAL_TRAIL_KEYS:
                source = np.asarray(state[key])
                destination = np.asarray(render_state[key])
                if source.ndim >= 1 and destination.ndim >= 1:
                    destination[global_row] = source[local_index]
            continue
        if new_cursor > old_cursor:
            for key in _RENDER_STATE_VISUAL_TRAIL_KEYS:
                if key == "visual_trail_write_cursor":
                    continue
                source = np.asarray(state[key])
                destination = np.asarray(render_state[key])
                destination[global_row, old_cursor:new_cursor] = source[
                    local_index,
                    old_cursor:new_cursor,
                ]
        destination_cursor[global_row] = source_cursor[local_index]


def _invalidate_visual_trail_render_state_rows(
    render_state: dict[str, np.ndarray],
    rows: np.ndarray,
) -> None:
    row_values = np.asarray(rows, dtype=np.int64).reshape(-1)
    if row_values.size == 0:
        return
    cursor = render_state.get("visual_trail_write_cursor")
    if cursor is None:
        return
    np.asarray(cursor)[row_values] = -1


def _write_persistent_compact_render_state_rows(
    render_state: dict[str, np.ndarray],
    *,
    rows: np.ndarray,
    state: Mapping[str, np.ndarray],
    player_count: int,
) -> dict[str, float]:
    """Write actor-local env state directly into persistent compact render buffers."""

    row_values = np.asarray(rows, dtype=np.int64).reshape(-1)
    timings = {field: 0.0 for field in _ACTOR_RENDER_STATE_WRITE_TIMING_FIELDS}
    if row_values.size == 0:
        return timings
    slot_capacity = int(np.asarray(render_state["trail_x"]).shape[1])
    player_count_int = int(player_count)
    row_slice = _contiguous_row_slice(row_values, limit=render_state["trail_x"].shape[0])
    row_target: Any = row_slice if row_slice is not None else row_values

    started = time.perf_counter()
    visual_pos = np.asarray(state["visual_trail_pos"])
    trail_slots = min(slot_capacity, int(visual_pos.shape[1]))
    if trail_slots:
        render_state["trail_x"][row_target, :trail_slots] = visual_pos[
            : row_values.size,
            :trail_slots,
            0,
        ]
        render_state["trail_y"][row_target, :trail_slots] = visual_pos[
            : row_values.size,
            :trail_slots,
            1,
        ]
        render_state["trail_radius"][row_target, :trail_slots] = np.asarray(
            state["visual_trail_radius"],
        )[: row_values.size, :trail_slots]
        render_state["trail_owner"][row_target, :trail_slots] = np.asarray(
            state["visual_trail_owner"],
            dtype=np.int32,
        )[: row_values.size, :trail_slots]
        render_state["trail_break_before"][row_target, :trail_slots] = np.asarray(
            state.get(
                "visual_trail_break_before",
                np.zeros((row_values.size, trail_slots), dtype=np.uint8),
            ),
            dtype=np.uint8,
        )[: row_values.size, :trail_slots]
        active = np.asarray(state["visual_trail_active"], dtype=np.uint8)[
            : row_values.size,
            :trail_slots,
        ]
        cursor = np.clip(
            np.asarray(
                state.get(
                    "visual_trail_write_cursor",
                    np.full((row_values.size,), trail_slots, dtype=np.int32),
                ),
                dtype=np.int32,
            )[: row_values.size],
            0,
            trail_slots,
        ).astype(np.int32, copy=False)
        slots = np.arange(trail_slots, dtype=np.int32)[None, :]
        render_state["trail_active"][row_target, :trail_slots] = np.where(
            slots < cursor[:, None],
            active,
            0,
        ).astype(np.uint8, copy=False)
        render_state["trail_write_cursor"][row_target] = cursor
    if trail_slots < slot_capacity:
        render_state["trail_x"][row_target, trail_slots:] = 0.0
        render_state["trail_y"][row_target, trail_slots:] = 0.0
        render_state["trail_radius"][row_target, trail_slots:] = 0.0
        render_state["trail_owner"][row_target, trail_slots:] = -1
        render_state["trail_active"][row_target, trail_slots:] = 0
        render_state["trail_break_before"][row_target, trail_slots:] = 0
    timings["actor_render_state_write_visual_trail_sec"] += _elapsed(started)

    started = time.perf_counter()
    pos = np.asarray(state["pos"])[: row_values.size, :player_count_int]
    render_state["head_x"][row_target] = pos[..., 0]
    render_state["head_y"][row_target] = pos[..., 1]
    render_state["head_radius"][row_target] = np.asarray(state["radius"])[
        : row_values.size,
        :player_count_int,
    ]
    alive = np.asarray(state["alive"], dtype=np.uint8)[: row_values.size, :player_count_int]
    present = np.asarray(state.get("present", state["alive"]), dtype=np.uint8)[
        : row_values.size,
        :player_count_int,
    ]
    render_state["head_alive"][row_target] = (alive & present).astype(np.uint8, copy=False)
    render_state["avatar_color"][row_target] = np.asarray(
        state.get(
            "avatar_color",
            np.arange(player_count_int, dtype=np.int32)[None, :].repeat(
                row_values.size,
                axis=0,
            ),
        ),
        dtype=np.int32,
    )[: row_values.size, :player_count_int]
    timings["actor_render_state_write_player_sec"] += _elapsed(started)

    started = time.perf_counter()
    bonus_capacity = int(np.asarray(render_state["bonus_active"]).shape[1])
    if bonus_capacity:
        if "bonus_active" in state:
            bonus_slots = min(bonus_capacity, int(np.asarray(state["bonus_active"]).shape[1]))
            if bonus_slots:
                bonus_pos = np.asarray(state["bonus_pos"])[: row_values.size, :bonus_slots]
                render_state["bonus_x"][row_target, :bonus_slots] = bonus_pos[..., 0]
                render_state["bonus_y"][row_target, :bonus_slots] = bonus_pos[..., 1]
                render_state["bonus_radius"][row_target, :bonus_slots] = np.asarray(
                    state["bonus_radius"],
                )[: row_values.size, :bonus_slots]
                render_state["bonus_active"][row_target, :bonus_slots] = np.asarray(
                    state["bonus_active"],
                    dtype=np.uint8,
                )[: row_values.size, :bonus_slots]
                render_state["bonus_type"][row_target, :bonus_slots] = np.asarray(
                    state["bonus_type"],
                    dtype=np.int32,
                )[: row_values.size, :bonus_slots]
            if bonus_slots < bonus_capacity:
                render_state["bonus_x"][row_target, bonus_slots:] = 0.0
                render_state["bonus_y"][row_target, bonus_slots:] = 0.0
                render_state["bonus_radius"][row_target, bonus_slots:] = 0.0
                render_state["bonus_active"][row_target, bonus_slots:] = 0
                render_state["bonus_type"][row_target, bonus_slots:] = 1
        else:
            render_state["bonus_x"][row_target] = 0.0
            render_state["bonus_y"][row_target] = 0.0
            render_state["bonus_radius"][row_target] = 0.0
            render_state["bonus_active"][row_target] = 0
            render_state["bonus_type"][row_target] = 1
    timings["actor_render_state_write_bonus_sec"] += _elapsed(started)
    return timings


def _contiguous_row_slice(row_values: np.ndarray, *, limit: int) -> slice | None:
    rows = np.asarray(row_values, dtype=np.int64).reshape(-1)
    if rows.size == 0:
        return slice(0, 0)
    start = int(rows[0])
    stop = start + int(rows.size)
    if start < 0 or stop > int(limit):
        return None
    if bool(np.array_equal(rows, np.arange(start, stop, dtype=np.int64))):
        return slice(start, stop)
    return None


def _render_state_write_timing_field(key: str) -> str:
    if key in _RENDER_STATE_VISUAL_TRAIL_KEYS:
        return "actor_render_state_write_visual_trail_sec"
    if key in _RENDER_STATE_PLAYER_KEYS:
        return "actor_render_state_write_player_sec"
    if key.startswith("bonus_"):
        return "actor_render_state_write_bonus_sec"
    return "actor_render_state_write_other_sec"


def _merge_render_state(
    payloads: list[HybridActorStepPayload],
    *,
    batch_size: int,
    state_attr: str = "render_state",
) -> dict[str, np.ndarray]:
    render_payloads = [payload for payload in payloads if getattr(payload, state_attr) is not None]
    if not render_payloads:
        raise ValueError("renderer-backed hybrid observation requires render_state payloads")

    merged: dict[str, np.ndarray] = {}
    first_state = getattr(render_payloads[0], state_attr)
    if first_state is None:
        raise ValueError("missing render_state")
    for key, first_value in first_state.items():
        first = np.asarray(first_value)
        if first.ndim == 0:
            merged[key] = first.copy()
            continue
        if first.shape[0] != render_payloads[0].global_rows.shape[0]:
            continue
        out = np.empty((batch_size, *first.shape[1:]), dtype=first.dtype)
        filled = np.zeros(batch_size, dtype=np.bool_)
        for payload in render_payloads:
            state = getattr(payload, state_attr)
            if state is None or key not in state:
                raise ValueError(f"missing render_state key {key!r}")
            value = np.asarray(state[key])
            rows = np.asarray(payload.global_rows, dtype=np.int64)
            expected_shape = (rows.shape[0], *first.shape[1:])
            if value.shape != expected_shape:
                raise ValueError(
                    f"render_state key {key!r} shape mismatch; "
                    f"got {value.shape}, expected {expected_shape}"
                )
            out[rows] = value
            filled[rows] = True
        if not bool(filled.all()):
            missing = np.flatnonzero(~filled).astype(int).tolist()
            raise ValueError(f"render_state key {key!r} missing rows {missing}")
        merged[key] = out
    return merged


def _empty_timings() -> dict[str, float]:
    return {field: 0.0 for field in HYBRID_OBSERVATION_TIMING_FIELDS}


def _validate_config(config: HybridObservationProfileConfig) -> None:
    if int(config.batch_size) < 1:
        raise ValueError("batch_size must be positive")
    if int(config.actor_count) < 1:
        raise ValueError("actor_count must be positive")
    if int(config.actor_count) > int(config.batch_size):
        raise ValueError("actor_count cannot exceed batch_size")
    if int(config.player_count) < 2:
        raise ValueError("player_count must be at least 2")
    if str(config.death_mode) not in vector_runtime.DEATH_MODES:
        raise ValueError("death_mode must be 'normal' or 'profile_no_death'")
    if int(config.steps) < 1:
        raise ValueError("steps must be positive")
    if int(config.warmup_steps) < 0:
        raise ValueError("warmup_steps must be non-negative")
    if str(config.resident_replay_snapshot_mode) not in RESIDENT_REPLAY_SNAPSHOT_MODES:
        allowed = ", ".join(RESIDENT_REPLAY_SNAPSHOT_MODES)
        raise ValueError(
            f"resident_replay_snapshot_mode must be one of {allowed}; "
            f"got {config.resident_replay_snapshot_mode!r}"
        )
    if str(config.stack_storage_dtype) not in HYBRID_STACK_STORAGE_DTYPES:
        allowed = ", ".join(HYBRID_STACK_STORAGE_DTYPES)
        raise ValueError(
            f"stack_storage_dtype must be one of {allowed}; got {config.stack_storage_dtype!r}"
        )
    if not bool(config.update_host_observation_stack) and str(config.stack_storage_dtype) != (
        HYBRID_STACK_STORAGE_DTYPE_UINT8
    ):
        raise ValueError("update_host_observation_stack=False requires uint8 stack storage")
    if bool(config.resident_observation_search):
        if bool(config.update_host_observation_stack):
            raise ValueError(
                "resident_observation_search=True requires update_host_observation_stack=False"
            )
        if str(config.stack_storage_dtype) != HYBRID_STACK_STORAGE_DTYPE_UINT8:
            raise ValueError("resident_observation_search=True requires uint8 stack storage")
        if not bool(config.refresh_observation_stack):
            raise ValueError(
                "resident_observation_search=True requires refresh_observation_stack=True"
            )
        if bool(config.materialize_scalar_timestep):
            raise ValueError(
                "resident_observation_search=True requires materialize_scalar_timestep=False"
            )
    if bool(config.compact_owner_mechanics_step_boundary) and not bool(
        config.compact_owner_action_step_boundary
    ):
        raise ValueError(
            "compact_owner_mechanics_step_boundary requires "
            "compact_owner_action_step_boundary"
        )


def _elapsed(started: float) -> float:
    return max(0.0, time.perf_counter() - started)


def _process_maxrss_raw() -> int:
    try:
        import resource

        return int(resource.getrusage(resource.RUSAGE_SELF).ru_maxrss)
    except Exception:
        return 0


